//! ISO-BMFF / MP4 A/V muxer: ONE faststart MP4 with TWO tracks —
//! trak#1 = all-intra AVC/H.264 video, trak#2 = AAC-LC audio.
//!
//! Pure Rust, std+alloc only, no external crates, no threads, no ffmpeg. wasm32-safe.
//! Pairs the sovereign video encoder (`h264_*`) with the sovereign audio encoder (`aac`)
//! so a Worker-rendered clip carries sound.
//!
//! # Box layout (FASTSTART — moov before mdat)
//!
//! ```text
//! ftyp
//! moov
//!   mvhd                         (timescale 1000, duration = max(video,audio) ms, next_track_id=3)
//!   trak  (track_id=1, VIDEO)
//!     tkhd
//!     mdia
//!       mdhd  (timescale=fps)
//!       hdlr  ('vide')
//!       minf
//!         vmhd
//!         dinf/dref/url
//!         stbl
//!           stsd/avc1/avcC
//!           stts (delta=1) / stsc / stsz / stco→video chunk
//!   trak  (track_id=2, AUDIO)
//!     tkhd
//!     mdia
//!       mdhd  (timescale=sample_rate)
//!       hdlr  ('soun')
//!       minf
//!         smhd
//!         dinf/dref/url
//!         stbl
//!           stsd/mp4a/esds
//!           stts (delta=1024) / stsc / stsz / stco→audio chunk
//! mdat
//!   <video samples…><audio frames…>     (two chunks, video first)
//! ```
//!
//! # esds (the fiddly part)
//!
//! ```text
//! esds (FullBox v0)
//!   ES_Descriptor                  tag 0x03
//!     ES_ID            u16 = 0
//!     flags            u8  = 0
//!     DecoderConfigDescriptor      tag 0x04
//!       objectTypeIndication u8  = 0x40   (Audio ISO/IEC 14496-3)
//!       streamType/upstream  u8  = (0x05<<2)|0x01 = 0x15  (AudioStream | reserved bit)
//!       bufferSizeDB         u24 = 0
//!       maxBitrate           u32 = 0
//!       avgBitrate           u32 = 0
//!       DecoderSpecificInfo        tag 0x05
//!         <AudioSpecificConfig bytes (asc)>
//!     SLConfigDescriptor           tag 0x06
//!       predefined           u8  = 0x02
//! ```
//! Descriptor lengths use single-byte length encoding (all descriptors here are < 128 bytes).

/// Mux an all-intra AVC/H.264 video stream + an AAC-LC audio stream into ONE faststart MP4.
///
/// # Parameters
/// - `sps`, `pps`: raw SPS/PPS NAL bytes (incl. 1-byte NAL header), **without** start code.
/// - `video_samples`: per-frame AVCC payload (each = NAL units length-prefixed, 4-byte BE).
/// - `width`, `height`, `fps`: video geometry & rate (fps = video media timescale, delta=1).
/// - `asc`: AudioSpecificConfig bytes (from `aac::encode_aac_lc`).
/// - `audio_frames`: per-frame raw AAC access units (no ADTS header), 1024 samples/frame.
/// - `sample_rate`, `channels`: audio media timescale & channel count.
///
/// # Returns
/// A `Vec<u8>` containing a valid ISO-BMFF MP4 with moov before mdat and two decodable tracks.
pub fn mux_av_mp4(
    sps: &[u8],
    pps: &[u8],
    video_samples: &[Vec<u8>],
    width: u32,
    height: u32,
    fps: u32,
    asc: &[u8],
    audio_frames: &[Vec<u8>],
    sample_rate: u32,
    channels: u8,
) -> Vec<u8> {
    // ------------------------------------------------------------------ //
    // helpers
    // ------------------------------------------------------------------ //
    fn write_u8(buf: &mut Vec<u8>, v: u8) {
        buf.push(v);
    }
    fn write_u16(buf: &mut Vec<u8>, v: u16) {
        buf.extend_from_slice(&v.to_be_bytes());
    }
    fn write_u24(buf: &mut Vec<u8>, v: u32) {
        buf.push(((v >> 16) & 0xFF) as u8);
        buf.push(((v >> 8) & 0xFF) as u8);
        buf.push((v & 0xFF) as u8);
    }
    fn write_u32(buf: &mut Vec<u8>, v: u32) {
        buf.extend_from_slice(&v.to_be_bytes());
    }
    fn write_fourcc(buf: &mut Vec<u8>, cc: &[u8; 4]) {
        buf.extend_from_slice(cc);
    }
    fn write_zeros(buf: &mut Vec<u8>, n: usize) {
        buf.resize(buf.len() + n, 0);
    }
    fn begin_box(buf: &mut Vec<u8>, cc: &[u8; 4]) -> usize {
        let idx = buf.len();
        write_u32(buf, 0); // placeholder size
        write_fourcc(buf, cc);
        idx
    }
    fn end_box(buf: &mut Vec<u8>, start: usize) {
        let size = (buf.len() - start) as u32;
        buf[start..start + 4].copy_from_slice(&size.to_be_bytes());
    }
    // Single-byte-length MPEG-4 descriptor: tag, len, payload.
    fn descriptor(tag: u8, payload: &[u8]) -> Vec<u8> {
        let mut d = Vec::with_capacity(payload.len() + 2);
        d.push(tag);
        debug_assert!(payload.len() < 128, "descriptor payload too long for 1-byte length");
        d.push(payload.len() as u8);
        d.extend_from_slice(payload);
        d
    }

    // ------------------------------------------------------------------ //
    // durations
    // ------------------------------------------------------------------ //
    let nv = video_samples.len() as u32; // video sample count
    let na = audio_frames.len() as u32; // audio frame count

    let movie_timescale: u32 = 1000;

    // Video media timescale = fps; each sample delta = 1.
    let video_timescale: u32 = fps;
    let video_media_duration: u32 = nv; // nv × delta 1

    // Audio media timescale = sample_rate; each frame delta = 1024.
    let samples_per_frame: u32 = 1024;
    let audio_timescale: u32 = sample_rate;
    let audio_media_duration: u32 = na.saturating_mul(samples_per_frame);

    // Durations in movie timescale (ms).
    let video_dur_ms: u32 =
        if fps == 0 { 0 } else { ((nv as u64 * movie_timescale as u64) / fps as u64) as u32 };
    let audio_dur_ms: u32 = if sample_rate == 0 {
        0
    } else {
        ((audio_media_duration as u64 * movie_timescale as u64) / sample_rate as u64) as u32
    };
    let movie_duration: u32 = video_dur_ms.max(audio_dur_ms);

    // ------------------------------------------------------------------ //
    // ftyp
    // ------------------------------------------------------------------ //
    let ftyp: Vec<u8> = {
        let mut b = Vec::new();
        let s = begin_box(&mut b, b"ftyp");
        write_fourcc(&mut b, b"isom");
        write_u32(&mut b, 0x0200);
        write_fourcc(&mut b, b"isom");
        write_fourcc(&mut b, b"iso2");
        write_fourcc(&mut b, b"avc1");
        write_fourcc(&mut b, b"mp41");
        end_box(&mut b, s);
        b
    };

    // ================================================================== //
    // VIDEO TRACK (track_id = 1)
    // ================================================================== //
    let avcc: Vec<u8> = {
        let mut b = Vec::new();
        let s = begin_box(&mut b, b"avcC");
        write_u8(&mut b, 1); // configurationVersion
        write_u8(&mut b, if sps.len() > 1 { sps[1] } else { 0 });
        write_u8(&mut b, if sps.len() > 2 { sps[2] } else { 0 });
        write_u8(&mut b, if sps.len() > 3 { sps[3] } else { 0 });
        write_u8(&mut b, 0xFF); // lengthSizeMinusOne = 3
        write_u8(&mut b, 0xE1); // numOfSPS = 1
        write_u16(&mut b, sps.len() as u16);
        b.extend_from_slice(sps);
        write_u8(&mut b, 0x01); // numOfPPS = 1
        write_u16(&mut b, pps.len() as u16);
        b.extend_from_slice(pps);
        end_box(&mut b, s);
        b
    };

    let avc1: Vec<u8> = {
        let mut b = Vec::new();
        let s = begin_box(&mut b, b"avc1");
        write_zeros(&mut b, 6);
        write_u16(&mut b, 1); // data_reference_index
        write_zeros(&mut b, 2);
        write_zeros(&mut b, 2);
        write_zeros(&mut b, 12);
        write_u16(&mut b, width as u16);
        write_u16(&mut b, height as u16);
        write_u32(&mut b, 0x0048_0000);
        write_u32(&mut b, 0x0048_0000);
        write_zeros(&mut b, 4);
        write_u16(&mut b, 1); // frame_count
        write_zeros(&mut b, 32); // compressorname
        write_u16(&mut b, 0x0018); // depth
        write_u16(&mut b, 0xFFFF); // pre_defined = -1
        b.extend_from_slice(&avcc);
        end_box(&mut b, s);
        b
    };

    let v_stsd: Vec<u8> = {
        let mut b = Vec::new();
        let s = begin_box(&mut b, b"stsd");
        write_u32(&mut b, 0);
        write_u32(&mut b, 1);
        b.extend_from_slice(&avc1);
        end_box(&mut b, s);
        b
    };

    let v_stts: Vec<u8> = {
        let mut b = Vec::new();
        let s = begin_box(&mut b, b"stts");
        write_u32(&mut b, 0);
        write_u32(&mut b, 1); // entry_count
        write_u32(&mut b, nv); // sample_count
        write_u32(&mut b, 1); // sample_delta = 1
        end_box(&mut b, s);
        b
    };

    let v_stsc: Vec<u8> = {
        let mut b = Vec::new();
        let s = begin_box(&mut b, b"stsc");
        write_u32(&mut b, 0);
        write_u32(&mut b, 1); // entry_count
        write_u32(&mut b, 1); // first_chunk
        write_u32(&mut b, nv); // samples_per_chunk (all in one chunk)
        write_u32(&mut b, 1); // sample_description_index
        end_box(&mut b, s);
        b
    };

    let v_stsz: Vec<u8> = {
        let mut b = Vec::new();
        let s = begin_box(&mut b, b"stsz");
        write_u32(&mut b, 0);
        write_u32(&mut b, 0); // sample_size = 0 (variable)
        write_u32(&mut b, nv);
        for sample in video_samples {
            write_u32(&mut b, sample.len() as u32);
        }
        end_box(&mut b, s);
        b
    };

    // stco — single chunk; remember the offset-field position WITHIN v_stco so we
    // can locate it inside the assembled moov via a marker search.
    let v_stco: Vec<u8> = {
        let mut b = Vec::new();
        let s = begin_box(&mut b, b"stco");
        write_u32(&mut b, 0); // version+flags
        write_u32(&mut b, 1); // entry_count
        write_u32(&mut b, V_STCO_SENTINEL); // placeholder chunk_offset (patched below)
        end_box(&mut b, s);
        b
    };

    let v_stbl: Vec<u8> = {
        let mut b = Vec::new();
        let s = begin_box(&mut b, b"stbl");
        b.extend_from_slice(&v_stsd);
        b.extend_from_slice(&v_stts);
        b.extend_from_slice(&v_stsc);
        b.extend_from_slice(&v_stsz);
        b.extend_from_slice(&v_stco);
        end_box(&mut b, s);
        b
    };

    let vmhd: Vec<u8> = {
        let mut b = Vec::new();
        let s = begin_box(&mut b, b"vmhd");
        write_u32(&mut b, 0x0000_0001); // version=0, flags=1
        write_u16(&mut b, 0);
        write_u16(&mut b, 0);
        write_u16(&mut b, 0);
        write_u16(&mut b, 0);
        end_box(&mut b, s);
        b
    };

    fn make_dinf() -> Vec<u8> {
        fn write_u32(buf: &mut Vec<u8>, v: u32) {
            buf.extend_from_slice(&v.to_be_bytes());
        }
        fn begin_box(buf: &mut Vec<u8>, cc: &[u8; 4]) -> usize {
            let idx = buf.len();
            write_u32(buf, 0);
            buf.extend_from_slice(cc);
            idx
        }
        fn end_box(buf: &mut Vec<u8>, start: usize) {
            let size = (buf.len() - start) as u32;
            buf[start..start + 4].copy_from_slice(&size.to_be_bytes());
        }
        let mut b = Vec::new();
        let s = begin_box(&mut b, b"dinf");
        let dr = begin_box(&mut b, b"dref");
        write_u32(&mut b, 0);
        write_u32(&mut b, 1); // entry_count
        let u = begin_box(&mut b, b"url ");
        write_u32(&mut b, 0x0000_0001); // self-contained
        end_box(&mut b, u);
        end_box(&mut b, dr);
        end_box(&mut b, s);
        b
    }
    let dinf = make_dinf();

    let v_minf: Vec<u8> = {
        let mut b = Vec::new();
        let s = begin_box(&mut b, b"minf");
        b.extend_from_slice(&vmhd);
        b.extend_from_slice(&dinf);
        b.extend_from_slice(&v_stbl);
        end_box(&mut b, s);
        b
    };

    let v_mdhd: Vec<u8> = {
        let mut b = Vec::new();
        let s = begin_box(&mut b, b"mdhd");
        write_u32(&mut b, 0);
        write_u32(&mut b, 0);
        write_u32(&mut b, 0);
        write_u32(&mut b, video_timescale);
        write_u32(&mut b, video_media_duration);
        write_u16(&mut b, 0x55C4); // 'und'
        write_u16(&mut b, 0);
        end_box(&mut b, s);
        b
    };

    let v_hdlr: Vec<u8> = {
        let mut b = Vec::new();
        let s = begin_box(&mut b, b"hdlr");
        write_u32(&mut b, 0);
        write_u32(&mut b, 0);
        write_fourcc(&mut b, b"vide");
        write_zeros(&mut b, 12);
        b.extend_from_slice(b"VideoHandler\0");
        end_box(&mut b, s);
        b
    };

    let v_mdia: Vec<u8> = {
        let mut b = Vec::new();
        let s = begin_box(&mut b, b"mdia");
        b.extend_from_slice(&v_mdhd);
        b.extend_from_slice(&v_hdlr);
        b.extend_from_slice(&v_minf);
        end_box(&mut b, s);
        b
    };

    let v_tkhd: Vec<u8> = {
        let mut b = Vec::new();
        let s = begin_box(&mut b, b"tkhd");
        write_u32(&mut b, 0x0000_0007); // enabled|in-movie|in-preview
        write_u32(&mut b, 0);
        write_u32(&mut b, 0);
        write_u32(&mut b, 1); // track_id = 1
        write_zeros(&mut b, 4);
        write_u32(&mut b, video_dur_ms);
        write_zeros(&mut b, 8);
        write_u16(&mut b, 0); // layer
        write_u16(&mut b, 0); // alternate_group
        write_u16(&mut b, 0); // volume (video = 0)
        write_u16(&mut b, 0);
        write_u32(&mut b, 0x0001_0000);
        write_u32(&mut b, 0);
        write_u32(&mut b, 0);
        write_u32(&mut b, 0);
        write_u32(&mut b, 0x0001_0000);
        write_u32(&mut b, 0);
        write_u32(&mut b, 0);
        write_u32(&mut b, 0);
        write_u32(&mut b, 0x4000_0000);
        write_u32(&mut b, width << 16);
        write_u32(&mut b, height << 16);
        end_box(&mut b, s);
        b
    };

    let v_trak: Vec<u8> = {
        let mut b = Vec::new();
        let s = begin_box(&mut b, b"trak");
        b.extend_from_slice(&v_tkhd);
        b.extend_from_slice(&v_mdia);
        end_box(&mut b, s);
        b
    };

    // ================================================================== //
    // AUDIO TRACK (track_id = 2)
    // ================================================================== //

    // esds box
    let esds: Vec<u8> = {
        // DecoderSpecificInfo (tag 0x05) = ASC bytes.
        let dsi = descriptor(0x05, asc);

        // DecoderConfigDescriptor (tag 0x04) payload.
        let mut dcd_payload = Vec::new();
        dcd_payload.push(0x40); // objectTypeIndication = Audio ISO/IEC 14496-3
        dcd_payload.push((0x05 << 2) | 0x01); // streamType=5 (Audio) | upstream=0 | reserved=1 => 0x15
        write_u24(&mut dcd_payload, 0); // bufferSizeDB
        write_u32(&mut dcd_payload, 0); // maxBitrate
        write_u32(&mut dcd_payload, 0); // avgBitrate
        dcd_payload.extend_from_slice(&dsi);
        let dcd = descriptor(0x04, &dcd_payload);

        // SLConfigDescriptor (tag 0x06) = predefined 0x02.
        let slc = descriptor(0x06, &[0x02]);

        // ES_Descriptor (tag 0x03) payload.
        let mut es_payload = Vec::new();
        write_u16(&mut es_payload, 0); // ES_ID
        es_payload.push(0); // flags
        es_payload.extend_from_slice(&dcd);
        es_payload.extend_from_slice(&slc);
        let es = descriptor(0x03, &es_payload);

        let mut b = Vec::new();
        let s = begin_box(&mut b, b"esds");
        write_u32(&mut b, 0); // FullBox version=0, flags=0
        b.extend_from_slice(&es);
        end_box(&mut b, s);
        b
    };

    let mp4a: Vec<u8> = {
        let mut b = Vec::new();
        let s = begin_box(&mut b, b"mp4a");
        write_zeros(&mut b, 6); // reserved
        write_u16(&mut b, 1); // data_reference_index
        // AudioSampleEntry version 0:
        write_u32(&mut b, 0); // reserved
        write_u32(&mut b, 0); // reserved
        write_u16(&mut b, channels.max(1) as u16); // channelcount
        write_u16(&mut b, 16); // samplesize
        write_u16(&mut b, 0); // pre_defined
        write_u16(&mut b, 0); // reserved
        write_u32(&mut b, sample_rate << 16); // samplerate (16.16)
        b.extend_from_slice(&esds);
        end_box(&mut b, s);
        b
    };

    let a_stsd: Vec<u8> = {
        let mut b = Vec::new();
        let s = begin_box(&mut b, b"stsd");
        write_u32(&mut b, 0);
        write_u32(&mut b, 1);
        b.extend_from_slice(&mp4a);
        end_box(&mut b, s);
        b
    };

    let a_stts: Vec<u8> = {
        let mut b = Vec::new();
        let s = begin_box(&mut b, b"stts");
        write_u32(&mut b, 0);
        write_u32(&mut b, 1); // entry_count
        write_u32(&mut b, na); // sample_count
        write_u32(&mut b, samples_per_frame); // sample_delta = 1024
        end_box(&mut b, s);
        b
    };

    let a_stsc: Vec<u8> = {
        let mut b = Vec::new();
        let s = begin_box(&mut b, b"stsc");
        write_u32(&mut b, 0);
        write_u32(&mut b, 1); // entry_count
        write_u32(&mut b, 1); // first_chunk
        write_u32(&mut b, na); // samples_per_chunk (all in one chunk)
        write_u32(&mut b, 1); // sample_description_index
        end_box(&mut b, s);
        b
    };

    let a_stsz: Vec<u8> = {
        let mut b = Vec::new();
        let s = begin_box(&mut b, b"stsz");
        write_u32(&mut b, 0);
        write_u32(&mut b, 0); // variable
        write_u32(&mut b, na);
        for frame in audio_frames {
            write_u32(&mut b, frame.len() as u32);
        }
        end_box(&mut b, s);
        b
    };

    let a_stco: Vec<u8> = {
        let mut b = Vec::new();
        let s = begin_box(&mut b, b"stco");
        write_u32(&mut b, 0);
        write_u32(&mut b, 1); // entry_count
        write_u32(&mut b, A_STCO_SENTINEL); // placeholder chunk_offset (patched below)
        end_box(&mut b, s);
        b
    };

    let a_stbl: Vec<u8> = {
        let mut b = Vec::new();
        let s = begin_box(&mut b, b"stbl");
        b.extend_from_slice(&a_stsd);
        b.extend_from_slice(&a_stts);
        b.extend_from_slice(&a_stsc);
        b.extend_from_slice(&a_stsz);
        b.extend_from_slice(&a_stco);
        end_box(&mut b, s);
        b
    };

    let smhd: Vec<u8> = {
        let mut b = Vec::new();
        let s = begin_box(&mut b, b"smhd");
        write_u32(&mut b, 0); // version+flags
        write_u16(&mut b, 0); // balance
        write_u16(&mut b, 0); // reserved
        end_box(&mut b, s);
        b
    };

    let a_minf: Vec<u8> = {
        let mut b = Vec::new();
        let s = begin_box(&mut b, b"minf");
        b.extend_from_slice(&smhd);
        b.extend_from_slice(&dinf);
        b.extend_from_slice(&a_stbl);
        end_box(&mut b, s);
        b
    };

    let a_mdhd: Vec<u8> = {
        let mut b = Vec::new();
        let s = begin_box(&mut b, b"mdhd");
        write_u32(&mut b, 0);
        write_u32(&mut b, 0);
        write_u32(&mut b, 0);
        write_u32(&mut b, audio_timescale);
        write_u32(&mut b, audio_media_duration);
        write_u16(&mut b, 0x55C4); // 'und'
        write_u16(&mut b, 0);
        end_box(&mut b, s);
        b
    };

    let a_hdlr: Vec<u8> = {
        let mut b = Vec::new();
        let s = begin_box(&mut b, b"hdlr");
        write_u32(&mut b, 0);
        write_u32(&mut b, 0);
        write_fourcc(&mut b, b"soun");
        write_zeros(&mut b, 12);
        b.extend_from_slice(b"SoundHandler\0");
        end_box(&mut b, s);
        b
    };

    let a_mdia: Vec<u8> = {
        let mut b = Vec::new();
        let s = begin_box(&mut b, b"mdia");
        b.extend_from_slice(&a_mdhd);
        b.extend_from_slice(&a_hdlr);
        b.extend_from_slice(&a_minf);
        end_box(&mut b, s);
        b
    };

    let a_tkhd: Vec<u8> = {
        let mut b = Vec::new();
        let s = begin_box(&mut b, b"tkhd");
        write_u32(&mut b, 0x0000_0007);
        write_u32(&mut b, 0);
        write_u32(&mut b, 0);
        write_u32(&mut b, 2); // track_id = 2
        write_zeros(&mut b, 4);
        write_u32(&mut b, audio_dur_ms);
        write_zeros(&mut b, 8);
        write_u16(&mut b, 0); // layer
        write_u16(&mut b, 0); // alternate_group
        write_u16(&mut b, 0x0100); // volume = 1.0 (audio track)
        write_u16(&mut b, 0);
        write_u32(&mut b, 0x0001_0000);
        write_u32(&mut b, 0);
        write_u32(&mut b, 0);
        write_u32(&mut b, 0);
        write_u32(&mut b, 0x0001_0000);
        write_u32(&mut b, 0);
        write_u32(&mut b, 0);
        write_u32(&mut b, 0);
        write_u32(&mut b, 0x4000_0000);
        write_u32(&mut b, 0); // width = 0 (audio)
        write_u32(&mut b, 0); // height = 0
        end_box(&mut b, s);
        b
    };

    let a_trak: Vec<u8> = {
        let mut b = Vec::new();
        let s = begin_box(&mut b, b"trak");
        b.extend_from_slice(&a_tkhd);
        b.extend_from_slice(&a_mdia);
        end_box(&mut b, s);
        b
    };

    // ------------------------------------------------------------------ //
    // mvhd
    // ------------------------------------------------------------------ //
    let mvhd: Vec<u8> = {
        let mut b = Vec::new();
        let s = begin_box(&mut b, b"mvhd");
        write_u32(&mut b, 0);
        write_u32(&mut b, 0);
        write_u32(&mut b, 0);
        write_u32(&mut b, movie_timescale);
        write_u32(&mut b, movie_duration);
        write_u32(&mut b, 0x0001_0000); // rate
        write_u16(&mut b, 0x0100); // volume
        write_u16(&mut b, 0);
        write_zeros(&mut b, 8);
        write_u32(&mut b, 0x0001_0000);
        write_u32(&mut b, 0);
        write_u32(&mut b, 0);
        write_u32(&mut b, 0);
        write_u32(&mut b, 0x0001_0000);
        write_u32(&mut b, 0);
        write_u32(&mut b, 0);
        write_u32(&mut b, 0);
        write_u32(&mut b, 0x4000_0000);
        write_zeros(&mut b, 24);
        write_u32(&mut b, 3); // next_track_id = 3 (two tracks used)
        end_box(&mut b, s);
        b
    };

    // ------------------------------------------------------------------ //
    // moov (first pass — stco placeholders still in place)
    // ------------------------------------------------------------------ //
    let moov_first: Vec<u8> = {
        let mut b = Vec::new();
        let s = begin_box(&mut b, b"moov");
        b.extend_from_slice(&mvhd);
        b.extend_from_slice(&v_trak);
        b.extend_from_slice(&a_trak);
        end_box(&mut b, s);
        b
    };

    // ------------------------------------------------------------------ //
    // Compute chunk offsets and patch both stco entries.
    //
    // File layout:  [ftyp][moov][8-byte mdat header][video samples][audio frames]
    //   mdat payload start  = ftyp.len() + moov.len() + 8
    //   video chunk offset  = mdat payload start
    //   audio chunk offset  = mdat payload start + sum(video sample sizes)
    // ------------------------------------------------------------------ //
    let video_payload_len: usize = video_samples.iter().map(|s| s.len()).sum();
    let audio_payload_len: usize = audio_frames.iter().map(|f| f.len()).sum();

    let mdat_payload_offset = ftyp.len() + moov_first.len() + 8;
    let video_chunk_offset = mdat_payload_offset as u32;
    let audio_chunk_offset = (mdat_payload_offset + video_payload_len) as u32;

    let moov = {
        let mut m = moov_first;
        // Patch the video placeholder (V_STCO_SENTINEL) and audio placeholder (A_STCO_SENTINEL).
        // Each placeholder is a unique 4-byte big-endian sentinel, so a single byte
        // search uniquely locates each stco chunk_offset field.
        let v_sentinel = V_STCO_SENTINEL.to_be_bytes();
        let a_sentinel = A_STCO_SENTINEL.to_be_bytes();
        let mut v_patched = false;
        let mut a_patched = false;
        let len = m.len();
        let mut i = 0usize;
        while i + 4 <= len {
            if !v_patched && m[i..i + 4] == v_sentinel {
                m[i..i + 4].copy_from_slice(&video_chunk_offset.to_be_bytes());
                v_patched = true;
                i += 4;
                continue;
            }
            if !a_patched && m[i..i + 4] == a_sentinel {
                m[i..i + 4].copy_from_slice(&audio_chunk_offset.to_be_bytes());
                a_patched = true;
                i += 4;
                continue;
            }
            i += 1;
        }
        debug_assert!(v_patched, "video stco placeholder not found");
        debug_assert!(a_patched, "audio stco placeholder not found");
        m
    };

    // ------------------------------------------------------------------ //
    // Assemble final file
    // ------------------------------------------------------------------ //
    let mdat_payload_len = video_payload_len + audio_payload_len;
    let mdat_box_size = 8 + mdat_payload_len;

    let mut out = Vec::with_capacity(ftyp.len() + moov.len() + mdat_box_size);
    out.extend_from_slice(&ftyp);
    out.extend_from_slice(&moov);
    out.extend_from_slice(&(mdat_box_size as u32).to_be_bytes());
    out.extend_from_slice(b"mdat");
    // Video chunk first, then audio chunk.
    for sample in video_samples {
        out.extend_from_slice(sample);
    }
    for frame in audio_frames {
        out.extend_from_slice(frame);
    }

    out
}

/// Unique sentinel placeholder for the VIDEO stco chunk_offset (patched after sizing).
const V_STCO_SENTINEL: u32 = 0xF1FE_0001;
/// Unique sentinel placeholder for the AUDIO stco chunk_offset (patched after sizing).
const A_STCO_SENTINEL: u32 = 0xF1FE_0002;

// ======================================================================== //
// Tests
// ======================================================================== //
#[cfg(test)]
mod tests {
    use super::*;

    fn find_fourcc(haystack: &[u8], needle: &[u8; 4]) -> Option<usize> {
        haystack.windows(4).position(|w| w == needle)
    }

    fn make_inputs() -> (Vec<u8>, Vec<u8>, Vec<Vec<u8>>, Vec<u8>, Vec<Vec<u8>>) {
        let sps = vec![0x67u8, 0x42, 0x00, 0x1E, 0xAB, 0xCD];
        let pps = vec![0x68u8, 0xCE, 0x38, 0x80];
        let make_vsample = |byte: u8| -> Vec<u8> {
            let nal: Vec<u8> = vec![0x65u8, byte, byte, byte, byte];
            let mut s = (nal.len() as u32).to_be_bytes().to_vec();
            s.extend_from_slice(&nal);
            s
        };
        let video = vec![make_vsample(0xAA), make_vsample(0xBB), make_vsample(0xCC)];
        // ASC for 44100 mono AAC-LC: aot=2, sfi=4, ch=1 => 0x12 0x08.
        let asc = vec![0x12u8, 0x08];
        let audio = vec![vec![0x21u8, 0x00, 0x49, 0x90], vec![0x21u8, 0x10, 0x49, 0x90]];
        (sps, pps, video, asc, audio)
    }

    #[test]
    fn av_box_tags_present() {
        let (sps, pps, video, asc, audio) = make_inputs();
        let mp4 = mux_av_mp4(&sps, &pps, &video, 64, 48, 12, &asc, &audio, 44100, 1);
        for tag in &[b"ftyp", b"moov", b"mdat", b"avcC", b"mp4a", b"esds", b"smhd", b"soun"] {
            assert!(
                find_fourcc(&mp4, *tag).is_some(),
                "missing box/tag '{}'",
                core::str::from_utf8(*tag).unwrap()
            );
        }
    }

    #[test]
    fn av_moov_before_mdat_and_ftyp_first() {
        let (sps, pps, video, asc, audio) = make_inputs();
        let mp4 = mux_av_mp4(&sps, &pps, &video, 64, 48, 12, &asc, &audio, 44100, 1);
        assert_eq!(&mp4[4..8], b"ftyp");
        let moov = find_fourcc(&mp4, b"moov").unwrap();
        let mdat = find_fourcc(&mp4, b"mdat").unwrap();
        assert!(moov < mdat, "moov must precede mdat");
    }

    #[test]
    fn av_no_placeholder_sentinels_remain() {
        let (sps, pps, video, asc, audio) = make_inputs();
        let mp4 = mux_av_mp4(&sps, &pps, &video, 64, 48, 12, &asc, &audio, 44100, 1);
        // The moov region must not contain either un-patched sentinel.
        let mdat = find_fourcc(&mp4, b"mdat").unwrap();
        let head = &mp4[..mdat];
        let v = V_STCO_SENTINEL.to_be_bytes();
        let a = A_STCO_SENTINEL.to_be_bytes();
        assert!(head.windows(4).all(|w| w != v), "video stco sentinel left un-patched");
        assert!(head.windows(4).all(|w| w != a), "audio stco sentinel left un-patched");
    }

    #[test]
    fn av_stco_offsets_point_into_mdat() {
        let (sps, pps, video, asc, audio) = make_inputs();
        let mp4 = mux_av_mp4(&sps, &pps, &video, 64, 48, 12, &asc, &audio, 44100, 1);

        let video_payload_len: usize = video.iter().map(|s| s.len()).sum();

        // Find BOTH stco boxes (video then audio in file order).
        let s1 = find_fourcc(&mp4, b"stco").unwrap();
        let s2 = s1 + 4 + find_fourcc(&mp4[s1 + 4..], b"stco").unwrap();

        let off1 = u32::from_be_bytes(mp4[s1 + 12..s1 + 16].try_into().unwrap()) as usize;
        let off2 = u32::from_be_bytes(mp4[s2 + 12..s2 + 16].try_into().unwrap()) as usize;

        // Video chunk = first video sample's first bytes.
        assert_eq!(&mp4[off1..off1 + 4], &video[0][..4]);
        // Audio chunk = video chunk + sum(video sizes) = first audio frame's bytes.
        assert_eq!(off2, off1 + video_payload_len);
        assert_eq!(&mp4[off2..off2 + 4], &audio[0][..4]);
    }
}
